const item = $input.first();
const binary = item.binary || {};
const chatInput = item.json.chatInput || item.json.body?.chatInput || '';
const sessionId = item.json.sessionId || item.json.body?.sessionId || 'default-session';

const binaryKeys = Object.keys(binary);
if (binaryKeys.length === 0) {
  throw new Error('No binary file found in input.');
}

const binaryKey = binaryKeys[0];
const binaryData = binary[binaryKey];

return {
  json: { chatInput, binaryKey, sessionId },
  binary: {
    data: binaryData
  }
};

const item = $input.first();
const pdfText = item.json.text || '';
const chatInput = $('Extract PDF via Code').first().json.chatInput || '';
const sessionId = $('Extract PDF via Code').first().json.sessionId || 'default-session';

if (!pdfText.trim()) {
  throw new Error('PDF appears to be image-based or empty. Please use a text-based PDF.');
}

const words = pdfText.trim().split(/\s+/);
const chunkSize = 400;
const overlap = 50;
const chunks = [];

for (let i = 0; i < words.length; i += chunkSize - overlap) {
  const chunk = words.slice(i, i + chunkSize).join(' ');
  if (chunk.trim()) chunks.push(chunk);
}

return chunks.map((chunk, index) => ({
  json: {
    chunk,
    chunkIndex: index,
    totalChunks: chunks.length,
    chatInput,
    sessionId,
    source: 'PDF Upload'
  }
}));

const items = $input.all();

if (!global.vectorStore) {
  global.vectorStore = {};
}

const sessionId = items[0]?.json.sessionId || 'default-session';
const chatInput = items[0]?.json.chatInput || '';

global.vectorStore[sessionId] = items.map(item => ({
  chunk: item.json.chunk,
  chunkIndex: item.json.chunkIndex,
  embedding: item.json.embedding?.values || []
}));

return [{
  json: {
    chatInput,
    sessionId,
    chunksStored: items.length,
    inputSource: 'PDF Upload',
    ragReady: true,
    studyContent: chatInput,
    userRequest: chatInput,
    retrievedContext: ''
  }
}];

const item = $input.first();
const chatInput = item.json.chatInput || item.json.body?.chatInput || '';
const sessionId = item.json.sessionId || item.json.body?.sessionId || 'default-session';

const store = global.vectorStore?.[sessionId] || [];
const hasVectorData = store.length > 0;

return [{
  json: {
    chatInput: chatInput.trim(),
    sessionId,
    studyContent: chatInput.trim(),
    userRequest: chatInput.trim(),
    inputSource: 'Text Input',
    hasVectorData
  }
}];

const item = $input.first();
const queryEmbedding = item.json.embedding?.values || [];

const chatInput = $('Build Context from Text').first().json.chatInput || '';
const sessionId = $('Build Context from Text').first().json.sessionId || 'default-session';

function cosineSim(a, b) {
  let dot = 0, normA = 0, normB = 0;
  for (let i = 0; i < a.length; i++) {
    dot   += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  return dot / (Math.sqrt(normA) * Math.sqrt(normB) + 1e-10);
}

const store = global.vectorStore?.[sessionId] || [];
let retrievedContext = '';

if (store.length > 0 && queryEmbedding.length > 0) {
  const scored = store.map(entry => ({
    chunk: entry.chunk,
    score: cosineSim(queryEmbedding, entry.embedding)
  }));
  scored.sort((a, b) => b.score - a.score);
  retrievedContext = scored.slice(0, 3).map(r => r.chunk).join('\n\n---\n\n');
}

return [{
  json: {
    chatInput,
    sessionId,
    studyContent: chatInput,
    userRequest: chatInput,
    inputSource: 'Text Input',
    retrievedContext,
    hasContext: retrievedContext.length > 0
  }
}];

const item = $input.first().json;
const studyContent = item.studyContent || '';
const userRequest  = item.userRequest  || '';
const inputSource  = item.inputSource  || 'Unknown';
const sessionId    = item.sessionId    || 'default-session';
const retrievedContext = item.retrievedContext || '';

const req = userRequest.toLowerCase();

let intent = 'explain';

if (/quiz|test me|question me|examine me/.test(req))                                           intent = 'quiz';
else if (/flashcard|flash card|key terms|key concepts|cards/.test(req))                        intent = 'flashcards';
else if (/revision plan|study plan|schedule|timetable|plan my/.test(req))                      intent = 'revision_plan';
else if (/explain|summarize|summary|what is|teach me|help me understand|tell me about|about/.test(req)) intent = 'explain';

const finalContent = studyContent.length > 30 ? studyContent : userRequest;

return [{
  json: {
    studyContent: finalContent,
    userRequest,
    inputSource,
    intent,
    sessionId,
    retrievedContext
  }
}];
